from __future__ import annotations

import asyncio
from collections.abc import Awaitable, Callable


async def run_tasks(
    tasks: list[Callable[[], Awaitable[None]]],
    max_concurrent: int,
) -> None:
    if max_concurrent < 1:
        raise ValueError("max_concurrent must be at least 1")

    current = asyncio.current_task()
    if current is None:
        raise RuntimeError("run_tasks() must be called from within a running task")

    task_iter = iter(tasks)
    in_flight: set[asyncio.Task[None]] = set()
    stop_starting = False
    first_error: BaseException | None = None

    def record_error(exc: BaseException) -> None:
        nonlocal first_error, stop_starting
        if first_error is None:
            first_error = exc
        stop_starting = True

    def start_available_tasks() -> None:
        nonlocal stop_starting
        while not stop_starting and len(in_flight) < max_concurrent and current.cancelling() == 0:
            try:
                task_factory = next(task_iter)
            except StopIteration:
                return

            try:
                coro = task_factory()
            except BaseException as exc:
                record_error(exc)
                return

            in_flight.add(asyncio.create_task(coro))

    async def wait_for_one(shielded: bool) -> tuple[set[asyncio.Task[None]], set[asyncio.Task[None]]]:
        waiter = asyncio.wait(in_flight, return_when=asyncio.FIRST_COMPLETED)
        if shielded:
            waiter = asyncio.shield(waiter)
        return await waiter

    def consume_done(done: set[asyncio.Task[None]]) -> None:
        for task in done:
            try:
                task.result()
            except BaseException as exc:
                record_error(exc)

    def uncancel_current_task() -> int:
        count = current.cancelling()
        for _ in range(count):
            current.uncancel()
        return count

    def restore_cancellation(count: int) -> None:
        for _ in range(count):
            current.cancel()

    start_available_tasks()

    try:
        while in_flight:
            shielded = current.cancelling() > 0
            try:
                done, pending = await wait_for_one(shielded)
            except asyncio.CancelledError as exc:
                record_error(exc)
                cancellation_count = uncancel_current_task()
                try:
                    while in_flight:
                        done, pending = await asyncio.wait(in_flight, return_when=asyncio.FIRST_COMPLETED)
                        in_flight = pending
                        consume_done(done)
                finally:
                    restore_cancellation(cancellation_count)
                raise

            in_flight = pending
            consume_done(done)
            start_available_tasks()
    finally:
        # If a task failed, keep draining already-started tasks so their cleanup
        # code can run before the exception escapes.
        if first_error is not None and in_flight:
            cancellation_count = 0
            if current.cancelling() > 0:
                cancellation_count = uncancel_current_task()
            try:
                while in_flight:
                    done, pending = await asyncio.wait(in_flight, return_when=asyncio.FIRST_COMPLETED)
                    in_flight = pending
                    consume_done(done)
            finally:
                if cancellation_count:
                    restore_cancellation(cancellation_count)

    if first_error is not None:
        raise first_error
